transform.script:
const taskText = triggeringMessage.content?.text || '';
if (!taskText || !taskText.trim()) throw new Error('ISSUE_OPENED has no text content — nothing to review');

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: '[REVIEW:VECTOR] Pass-through routing to vector tier',
    data: {
      operations: [
        {
          action: 'load_config',
          config: {
            base: 'docs-review-workflow',
            params: {
              tier: 'vector',
              analyst_level: 'level2',
              validator_count: 2,
              max_iterations: 4,
              max_tokens: 150000,
              validator_level: 'level2',
              artifact_scope: 'CHAIN',
              content_domain: 'GENERAL',
              has_test_content: false,
              is_chain: true,
              is_sensitive: false
            }
          }
        },
        {
          action: 'publish',
          topic: 'ISSUE_OPENED',
          content: { text: taskText },
          metadata: { _republished: true }
        }
      ]
    }
  }
};
